  1	import * as React from 'react';
  2	import {
  3	  StorageDashboard,
  4	  CAPACITY_QUERIES,
  5	} from '@odf/mco/components/mco-dashboard/queries';
  6	import { ACMManagedClusterKind } from '@odf/mco/types';
  7	import { ACMManagedClusterModel } from '@odf/shared';
  8	import { DataUnavailableError } from '@odf/shared/generic/Error';
  9	import { useCustomPrometheusPoll } from '@odf/shared/hooks/custom-prometheus-poll';
 10	import { ODFStorageSystem } from '@odf/shared/models';
 11	import ResourceLink from '@odf/shared/resource-link/resource-link';
 12	import Table from '@odf/shared/table/table';
 13	import { HumanizeResult } from '@odf/shared/types';
 14	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 15	import {
 16	  getGVK,
 17	  humanizeBinaryBytes,
 18	  referenceForGroupVersionKind,
 19	  referenceForModel,
 20	  getDashboardLink,
 21	} from '@odf/shared/utils';
 22	import {
 23	  PrometheusResult,
 24	  useK8sWatchResource,
 25	} from '@openshift-console/dynamic-plugin-sdk';
 26	import SearchIcon from '@patternfly/react-icons/dist/esm/icons/search-icon';
 27	import * as _ from 'lodash-es';
 28	import { TFunction } from 'react-i18next';
 29	import {
 30	  Progress,
 31	  ProgressMeasureLocation,
 32	  ProgressVariant,
 33	  Tooltip,
 34	  Button,
 35	  ButtonVariant,
 36	  TextInput,
 37	} from '@patternfly/react-core';
 38	import {
 39	  Card,
 40	  CardHeader,
 41	  CardBody,
 42	  CardTitle,
 43	  Flex,
 44	  FlexItem,
 45	} from '@patternfly/react-core';
 46	import { SortByDirection } from '@patternfly/react-table';
 47	import {
 48	  ACM_ENDPOINT,
 49	  CLUSTER_CLAIM_URL_NAME,
 50	  HUB_CLUSTER_NAME,
 51	} from '../../../../constants';
 52	import './capacity-card.scss';
 53	
 54	type CapacityMetricDatum = {
 55	  systemName: string;
 56	  namespace: string;
 57	  targetKind: string;
 58	  clusterName: string;
 59	  totalValue: HumanizeResult;
 60	  usedValue: HumanizeResult;
 61	  clusterURL: string;
 62	};
 63	
 64	type GetRow = (
 65	  args: CapacityMetricDatum,
 66	  index: number
 67	) => [React.ReactNode, React.ReactNode, React.ReactNode, React.ReactNode];
 68	
 69	type CapacityMetricDatumMap = { string: CapacityMetricDatum };
 70	
 71	type ManagedClusterLinkMap = { string: string };
 72	
 73	type ClusterClaimObject = { name: string; value: string };
 74	
 75	const getUniqueKey = (
 76	  systemName: string,
 77	  namespace: string,
 78	  clusterName: string
 79	) => `${systemName}-${namespace}-${clusterName}`;
 80	
 81	const getClusterURL = (clusterClaimsList: ClusterClaimObject[]) =>
 82	  clusterClaimsList?.find(
 83	    (claimObj: ClusterClaimObject) => claimObj?.name === CLUSTER_CLAIM_URL_NAME
 84	  )?.value || undefined;
 85	
 86	const getPercentage = (usedValue: HumanizeResult, totalValue: HumanizeResult) =>
 87	  (humanizeBinaryBytes(usedValue.value, usedValue.unit, totalValue.unit).value /
 88	    totalValue.value) *
 89	  100;
 90	
 91	const systemNameSort = (
 92	  a: CapacityMetricDatum,
 93	  b: CapacityMetricDatum,
 94	  c: SortByDirection
 95	) => {
 96	  const negation = c !== SortByDirection.asc;
 97	  const sortVal = a.systemName.localeCompare(b.systemName);
 98	  return negation ? -sortVal : sortVal;
 99	};
100	
101	const clusterNameSort = (
102	  a: CapacityMetricDatum,
103	  b: CapacityMetricDatum,
104	  c: SortByDirection
105	) => {
106	  const negation = c !== SortByDirection.asc;
107	  const sortVal = a.clusterName.localeCompare(b.clusterName);
108	  return negation ? -sortVal : sortVal;
109	};
110	
111	const metricsSort = (
112	  a: CapacityMetricDatum,
113	  b: CapacityMetricDatum,
114	  c: SortByDirection
115	) => {
116	  const negation = c !== SortByDirection.asc;
117	  /**
118	   * If total capacity is not present (mcg standalone),
119	   * setting percentage as 100, will be used for sorting the rows based on used capacity %.
120	   */
121	  const percentageA = !!a?.totalValue
122	    ? getPercentage(a?.usedValue, a?.totalValue)
123	    : 100;
124	  const percentageB = !!b?.totalValue
125	    ? getPercentage(b?.usedValue, b?.totalValue)
126	    : 100;
127	  const sortVal = percentageA - percentageB || 0;
128	  return negation ? -sortVal : sortVal;
129	};
130	
131	const headerColumns = (t: TFunction) => [
132	  {
133	    columnName: t('plugin__odf-console~Name'),
134	    className: 'pf-v6-u-w-25',
135	    sortFunction: systemNameSort,
136	  },
137	  {
138	    columnName: t('plugin__odf-console~Cluster name'),
139	    className: 'pf-v5-u-w-20',
140	    sortFunction: clusterNameSort,
141	  },
142	  {
143	    columnName: t('plugin__odf-console~Used Capacity %'),
144	    className: 'pf-v6-u-w-25',
145	    sortFunction: metricsSort,
146	  },
147	  {
148	    columnName: t('plugin__odf-console~Used / Total'),
149	    className: 'pf-v5-u-w-30',
150	  },
151	];
152	
153	const getRow: GetRow = (
154	  {
155	    systemName,
156	    namespace: systemNamespace,
157	    targetKind,
158	    clusterName,
159	    totalValue,
160	    usedValue,
161	    clusterURL,
162	  },
163	  index
164	) => {
165	  const { apiGroup, apiVersion, kind } = getGVK(targetKind);
166	  const systemKind = referenceForGroupVersionKind(apiGroup)(apiVersion)(kind);
167	  const systemPath = getDashboardLink(systemKind, systemName, systemNamespace);
168	  const isPercentage = !!totalValue;
169	  const progress = isPercentage ? getPercentage(usedValue, totalValue) : 100;
170	  const value = isPercentage
171	    ? `${usedValue.string} / ${totalValue.string}`
172	    : usedValue.string;
173	  const variant = (() => {
174	    if (!totalValue) {
175	      return null;
176	    }
177	    if (progress >= 80) {
178	      return ProgressVariant.danger;
179	    }
180	    if (progress >= 75) {
181	      return ProgressVariant.warning;
182	    }
183	  })();
184	  const dataUnavailable = _.isNaN(progress);
185	
186	  return [
187	    <Tooltip key={`${systemName}${index}`} content={systemName}>
188	      <ResourceLink
189	        data-test="storage-system-link"
190	        link={`${clusterURL}/${systemPath}`}
191	        resourceModel={ODFStorageSystem}
192	        resourceName={systemName}
193	        className="odf-capacityCardLink--ellipsis"
194	        isExternalLink
195	      />
196	    </Tooltip>,
197	
198	    <Tooltip key={`${clusterName}${index}`} content={clusterName}>
199	      <div data-test="managed-cluster-name">{clusterName}</div>
200	    </Tooltip>,
201	
202	    !isPercentage ? (
203	      <Progress
204	        data-test="storage-system-used-capacity-percent"
205	        value={dataUnavailable ? null : progress}
206	        label={!dataUnavailable ? `${progress.toFixed(2)} %` : ''}
207	        size="md"
208	        measureLocation={
209	          !isPercentage
210	            ? ProgressMeasureLocation.none
211	            : ProgressMeasureLocation.outside
212	        }
213	        variant={variant}
214	      />
215	    ) : (
216	      <Tooltip
217	        key={index}
218	        content={!dataUnavailable ? <>{progress.toFixed(2)} %</> : null}
219	      >
220	        <Progress
221	          data-test="storage-system-used-capacity-percent"
222	          value={dataUnavailable ? null : progress}
223	          label={!dataUnavailable ? `${progress.toFixed(2)} %` : ''}
224	          size="md"
225	          measureLocation={ProgressMeasureLocation.outside}
226	          variant={variant}
227	        />
228	      </Tooltip>
229	    ),
230	
231	    <div
232	      data-test="storage-system-used-capacity"
233	      key="storage-system-used-capacity"
234	    >
235	      {dataUnavailable ? '-' : value}
236	    </div>,
237	  ];
238	};
239	
240	const SystemCapacityCard: React.FC = () => {
241	  const { t } = useCustomTranslation();
242	  const [updatefilteredData, setUpdateFilteredData] =
243	    React.useState<boolean>(true);
244	  const [unfilteredData, setUnfilteredData] = React.useState<
245	    CapacityMetricDatum[]
246	  >([]);
247	  const [filteredData, setFilteredData] = React.useState<CapacityMetricDatum[]>(
248	    []
249	  );
250	
251	  const [managedClusters, managedClustersLoaded, managedClustersError] =
252	    useK8sWatchResource<ACMManagedClusterKind[]>({
253	      kind: referenceForModel(ACMManagedClusterModel),
254	      isList: true,
255	      namespaced: false,
256	    });
257	
258	  const [usedCapacity, errorUsedCapacity, loadingUsedCapacity] =
259	    useCustomPrometheusPoll({
260	      endpoint: 'api/v1/query' as any,
261	      query: CAPACITY_QUERIES[StorageDashboard.USED_CAPACITY_FILE_BLOCK],
262	      basePath: ACM_ENDPOINT,
263	      cluster: HUB_CLUSTER_NAME,
264	    });
265	  const [totalCapacity, errorTotalCapacity, loadingTotalCapacity] =
266	    useCustomPrometheusPoll({
267	      endpoint: 'api/v1/query' as any,
268	      query: CAPACITY_QUERIES[StorageDashboard.TOTAL_CAPACITY_FILE_BLOCK],
269	      basePath: ACM_ENDPOINT,
270	      cluster: HUB_CLUSTER_NAME,
271	    });
272	
273	  React.useEffect(() => {
274	    const ManagedClusterLink: ManagedClusterLinkMap =
275	      managedClustersLoaded && !managedClustersError
276	        ? managedClusters?.reduce(
277	            (acc: ManagedClusterLinkMap, cluster: ACMManagedClusterKind) => {
278	              acc[cluster?.metadata?.name] = getClusterURL(
279	                cluster?.status?.clusterClaims
280	              );
281	              return acc;
282	            },
283	            {} as ManagedClusterLinkMap
284	          )
285	        : ({} as ManagedClusterLinkMap);
286	
287	    const dataMap: CapacityMetricDatumMap =
288	      !loadingUsedCapacity && !errorUsedCapacity
289	        ? usedCapacity?.data?.result?.reduce(
290	            (acc: CapacityMetricDatumMap, usedMetric: PrometheusResult) => {
291	              // ToDo (epic 4422): Assuming "namespace" in "odf_system.*"" metrics (except "odf_system_map" which is pushed by ODF opr and already has "target_namespace")
292	              // is where system is deployed (update query if needed).
293	              const systemName = usedMetric?.metric?.storage_system;
294	              const namespace = usedMetric?.metric?.target_namespace;
295	              const targetKind = usedMetric?.metric?.target_kind;
296	              const clusterName = usedMetric?.metric?.cluster;
297	              const clusterURL = ManagedClusterLink.hasOwnProperty(clusterName)
298	                ? ManagedClusterLink[clusterName]
299	                : undefined;
300	              acc[getUniqueKey(systemName, namespace, clusterName)] = {
301	                systemName,
302	                namespace,
303	                targetKind,
304	                clusterName,
305	                usedValue: humanizeBinaryBytes(usedMetric?.value?.[1]),
306	                totalValue: undefined,
307	                clusterURL,
308	              };
309	              return acc;
310	            },
311	            {} as CapacityMetricDatumMap
312	          )
313	        : ({} as CapacityMetricDatumMap);
314	
315	    !loadingTotalCapacity &&
316	      !errorTotalCapacity &&
317	      totalCapacity?.data?.result?.forEach((totalMetric: PrometheusResult) => {
318	        // ToDo (epic 4422): Assuming "namespace" in "odf_system.*"" metrics (except "odf_system_map" which is pushed by ODF opr and already has "target_namespace")
319	        // is where system is deployed (update query if needed).
320	        const dataMapKey = getUniqueKey(
321	          totalMetric?.metric?.storage_system,
322	          totalMetric?.metric?.target_namespace,
323	          totalMetric?.metric?.cluster
324	        );
325	        dataMap.hasOwnProperty(dataMapKey) &&
326	          (dataMap[dataMapKey].totalValue = !!totalMetric?.value?.[1]
327	            ? humanizeBinaryBytes(totalMetric?.value?.[1])
328	            : undefined);
329	      });
330	
331	    const data: CapacityMetricDatum[] = _.map(
332	      dataMap,
333	      (metricDatumMap: CapacityMetricDatum) => metricDatumMap
334	    );
335	    setUnfilteredData(data);
336	    updatefilteredData && setFilteredData(data);
337	  }, [
338	    loadingUsedCapacity,
339	    loadingTotalCapacity,
340	    errorUsedCapacity,
341	    errorTotalCapacity,
342	    usedCapacity,
343	    totalCapacity,
344	    updatefilteredData,
345	    managedClusters,
346	    managedClustersLoaded,
347	    managedClustersError,
348	    setUnfilteredData,
349	    setFilteredData,
350	  ]);
351	
352	  const error = !_.isEmpty(errorTotalCapacity) || !_.isEmpty(errorUsedCapacity);
353	  const isLoading = loadingUsedCapacity && loadingTotalCapacity;
354	
355	  const onChange = (searchValue: string) => {
356	    if (searchValue === '') {
357	      setUpdateFilteredData(true);
358	      setFilteredData(unfilteredData);
359	    } else {
360	      setUpdateFilteredData(false);
361	      setFilteredData(
362	        unfilteredData?.filter((capacityData) =>
363	          capacityData?.clusterName
364	            .toLocaleLowerCase()
365	            .includes(searchValue.toLocaleLowerCase())
366	        )
367	      );
368	    }
369	  };
370	
371	  return (
372	    <Card data-test="capacity-card">
373	      <CardHeader>
374	        <Flex
375	          justifyContent={{ default: 'justifyContentSpaceBetween' }}
376	          className="odf-capacityCard__header--width"
377	        >
378	          <FlexItem>
379	            <CardTitle data-test="capacity-card-title">
380	              {t('Storage system capacity')}
381	            </CardTitle>
382	          </FlexItem>
383	          <FlexItem>
384	            <TextInput
385	              data-test="cluster-name-text"
386	              placeholder={t('Search by cluster name...')}
387	              name="clusterNameText"
388	              id="clusterNameText"
389	              type="text"
390	              className="odf-capacityCard__filter--width"
391	              aria-label={t('cluster name search')}
392	              onChange={(_event, searchValue: string) => onChange(searchValue)}
393	            />
394	            <Button
395	              variant={ButtonVariant.control}
396	              aria-label={t('cluster name search button')}
397	            >
398	              <SearchIcon />
399	            </Button>
400	          </FlexItem>
401	        </Flex>
402	      </CardHeader>
403	      <CardBody className="odf-capacityCard__table--overflow">
404	        {!error && !isLoading && (
405	          <Table
406	            columns={headerColumns(t)}
407	            rawData={filteredData as []}
408	            rowRenderer={getRow as any}
409	            ariaLabel={t('Capacity Card')}
410	          />
411	        )}
412	        {isLoading && !error && <CapacityCardLoading />}
413	        {((error && !isLoading) ||
414	          (!error && !isLoading && _.isEmpty(filteredData))) && (
415	          <div className="odf-capacityCard--error">
416	            <DataUnavailableError />
417	          </div>
418	        )}
419	      </CardBody>
420	    </Card>
421	  );
422	};
423	
424	export default SystemCapacityCard;
425	
426	const CapacityCardRowLoading: React.FC = () => (
427	  <div className="odf-capacityCardLoading-body__item">
428	    <div className="odf-capacityCardLoading-body__item-item__element odf-capacityCardLoading-body__item--thin" />
429	    <div className="odf-capacityCardLoading-body__item-item__element odf-capacityCardLoading-body__item--thin" />
430	    <div className="odf-capacityCardLoading-body__item-item__element odf-capacityCardLoading-body__item--thick" />
431	    <div className="odf-capacityCardLoading-body__item-item__element odf-capacityCardLoading-body__item--thin" />
432	  </div>
433	);
434	const CapacityCardLoading: React.FC = () => (
435	  <div className="odf-capacityCardLoading-body">
436	    <CapacityCardRowLoading />
437	    <CapacityCardRowLoading />
438	    <CapacityCardRowLoading />
439	    <CapacityCardRowLoading />
440	    <CapacityCardRowLoading />
441	  </div>
442	);

