  1	import * as React from 'react';
  2	import {
  3	  StorageDashboard,
  4	  CAPACITY_QUERIES,
  5	} from '@odf/mco/components/mco-dashboard/queries';
  6	import { ACMManagedClusterKind } from '@odf/mco/types';
  7	import { ACMManagedClusterModel } from '@odf/shared';
  8	import { DataUnavailableError } from '@odf/shared/generic/Error';
  9	import { useCustomPrometheusPoll } from '@odf/shared/hooks/custom-prometheus-poll';
 10	import { ODFStorageSystem } from '@odf/shared/models';
 11	import ResourceLink from '@odf/shared/resource-link/resource-link';
 12	import Table from '@odf/shared/table/table';
 13	import { HumanizeResult } from '@odf/shared/types';
 14	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 15	import {
 16	  getGVK,
 17	  humanizeBinaryBytes,
 18	  referenceForGroupVersionKind,
 19	  referenceForModel,
 20	  getDashboardLink,
 21	} from '@odf/shared/utils';
 22	import {
 23	  PrometheusResult,
 24	  useK8sWatchResource,
 25	} from '@openshift-console/dynamic-plugin-sdk';
 26	import SearchIcon from '@patternfly/react-icons/dist/esm/icons/search-icon';
 27	import * as _ from 'lodash-es';
 28	import { TFunction } from 'react-i18next';
 29	import {
 30	  Progress,
 31	  ProgressMeasureLocation,
 32	  ProgressVariant,
 33	  Tooltip,
 34	  Button,
 35	  ButtonVariant,
 36	  TextInput,
 37	} from '@patternfly/react-core';
 38	import {
 39	  Card,
 40	  CardHeader,
 41	  CardBody,
 42	  CardTitle,
 43	  Flex,
 44	  FlexItem,
 45	} from '@patternfly/react-core';
 46	import { SortByDirection } from '@patternfly/react-table';
 47	import {
 48	  ACM_ENDPOINT,
 49	  CLUSTER_CLAIM_URL_NAME,
 50	  HUB_CLUSTER_NAME,
 51	} from '../../../../constants';
 52	import './capacity-card.scss';
 53	
 54	type CapacityMetricDatum = {
 55	  systemName: string;
 56	  namespace: string;
 57	  targetKind: string;
 58	  clusterName: string;
 59	  totalValue: HumanizeResult;
 60	  usedValue: HumanizeResult;
 61	  clusterURL: string;
 62	};
 63	
 64	type GetRow = (
 65	  args: CapacityMetricDatum,
 66	  index: number
 67	) => [React.ReactNode, React.ReactNode, React.ReactNode, React.ReactNode];
 68	
 69	type CapacityMetricDatumMap = { string: CapacityMetricDatum };
 70	
 71	type ManagedClusterLinkMap = { string: string };
 72	
 73	type ClusterClaimObject = { name: string; value: string };
 74	
 75	const getUniqueKey = (
 76	  systemName: string,
 77	  namespace: string,
 78	  clusterName: string
 79	) => `${systemName}-${namespace}-${clusterName}`;
 80	
 81	const getClusterURL = (clusterClaimsList: ClusterClaimObject[]) =>
 82	  clusterClaimsList?.find(
 83	    (claimObj: ClusterClaimObject) => claimObj?.name === CLUSTER_CLAIM_URL_NAME
 84	  )?.value || undefined;
 85	
 86	const getPercentage = (usedValue: HumanizeResult, totalValue: HumanizeResult) =>
 87	  (humanizeBinaryBytes(usedValue.value, usedValue.unit, totalValue.unit).value /
 88	    totalValue.value) *
 89	  100;
 90	
 91	const systemNameSort = (
 92	  a: CapacityMetricDatum,
 93	  b: CapacityMetricDatum,
 94	  c: SortByDirection
 95	) => {
 96	  const negation = c !== SortByDirection.asc;
 97	  const sortVal = a.systemName.localeCompare(b.systemName);
 98	  return negation ? -sortVal : sortVal;
 99	};
100	
101	const clusterNameSort = (
102	  a: CapacityMetricDatum,
103	  b: CapacityMetricDatum,
104	  c: SortByDirection
105	) => {
106	  const negation = c !== SortByDirection.asc;
107	  const sortVal = a.clusterName.localeCompare(b.clusterName);
108	  return negation ? -sortVal : sortVal;
109	};
110	
111	const metricsSort = (
112	  a: CapacityMetricDatum,
113	  b: CapacityMetricDatum,
114	  c: SortByDirection
115	) => {
116	  const negation = c !== SortByDirection.asc;
117	  /**
118	   * If total capacity is not present (mcg standalone),
119	   * setting percentage as 100, will be used for sorting the rows based on used capacity %.
120	   */
121	  const percentageA = !!a?.totalValue
122	    ? getPercentage(a?.usedValue, a?.totalValue)
123	    : 100;
124	  const percentageB = !!b?.totalValue
125	    ? getPercentage(b?.usedValue, b?.totalValue)
126	    : 100;
127	  const sortVal = percentageA - percentageB || 0;
128	  return negation ? -sortVal : sortVal;
129	};
130	
131	const headerColumns = (t: TFunction) => [
132	  {
133	    columnName: t('plugin__odf-console~Name'),
134	    className: 'pf-v6-u-w-25',
135	    sortFunction: systemNameSort,
136	  },
137	  {
138	    columnName: t('plugin__odf-console~Cluster name'),
139	    className: 'pf-v5-u-w-20',
140	    sortFunction: clusterNameSort,
141	  },
142	  {
143	    columnName: t('plugin__odf-console~Used Capacity %'),
144	    className: 'pf-v6-u-w-25',
145	    sortFunction: metricsSort,
146	  },
147	  {
148	    columnName: t('plugin__odf-console~Used / Total'),
149	    className: 'pf-v5-u-w-30',
150	  },
151	];
152	
153	const getRow: GetRow = (
154	  {
155	    systemName,
156	    namespace: systemNamespace,
157	    targetKind,
158	    clusterName,
159	    totalValue,
160	    usedValue,
161	    clusterURL,
162	  },
163	  index
164	) => {
165	  const { apiGroup, apiVersion, kind } = getGVK(targetKind);
166	  const systemKind = referenceForGroupVersionKind(apiGroup)(apiVersion)(kind);
167	  const systemPath = getDashboardLink(systemKind, systemName, systemNamespace);
168	  const isPercentage = !!totalValue;
169	  const progress = isPercentage ? getPercentage(usedValue, totalValue) : 100;
170	  const value = isPercentage
171	    ? `${usedValue.string} / ${totalValue.string}`
172	    : usedValue.string;
173	  const variant = (() => {
174	    if (!totalValue) {
175	      return null;
176	    }
177	    if (progress >= 80) {
178	      return ProgressVariant.danger;
179	    }
180	    if (progress >= 75) {
181	      return ProgressVariant.warning;
182	    }
183	  })();
184	  const dataUnavailable = _.isNaN(progress);
185	
186	  return [
187	    <Tooltip key={`${systemName}${index}`} content={systemName}>
188	      <ResourceLink
189	        data-test="storage-system-link"
190	        link={`${clusterURL}/${systemPath}`}
191	        resourceModel={ODFStorageSystem}
192	        resourceName={systemName}
193	        className="odf-capacityCardLink--ellipsis"
194	        isExternalLink
195	      />
196	    </Tooltip>,
197	
198	    <Tooltip key={`${clusterName}${index}`} content={clusterName}>
199	      <div data-test="managed-cluster-name">{clusterName}</div>
200	    </Tooltip>,
201	
202	    !isPercentage ? (
203	      <Progress
204	        data-test="storage-system-used-capacity-percent"
205	        value={dataUnavailable ? null : progress}
206	        label={!dataUnavailable ? `${progress.toFixed(2)} %` : ''}
207	        size="md"
208	        measureLocation={
209	          !isPercentage
210	            ? ProgressMeasureLocation.none
211	            : ProgressMeasureLocation.outside
212	        }
213	        variant={variant}
214	      />
215	    ) : (
216	      <Tooltip
217	        key={index}
218	        content={!dataUnavailable ? <>{progress.toFixed(2)} %</> : null}
219	      >
220	        <Progress
221	          data-test="storage-system-used-capacity-percent"
222	          value={dataUnavailable ? null : progress}
223	          label={!dataUnavailable ? `${progress.toFixed(2)} %` : ''}
224	          size="md"
225	          measureLocation={ProgressMeasureLocation.outside}
226	          variant={variant}
227	        />
228	      </Tooltip>
229	    ),
230	
231	    <div
232	      data-test="storage-system-used-capacity"
233	      key="storage-system-used-capacity"
234	    >
235	      {dataUnavailable ? '-' : value}
236	    </div>,
237	  ];
238	};
